    @WebMethod(operationName = "processBulkImport")
    public String processBulkImport(@WebParam(name = "xmlData") String xmlData) {
        try {
            DocumentBuilder builder = documentBuilderFactory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(xmlData)));
            document.getDocumentElement().normalize();

            Map<String, Integer> importStats = new HashMap<>();
            
            dbConnection.setAutoCommit(false);
            
            try {
                NodeList batchNodes = document.getElementsByTagName("batch");
                for (int i = 0; i < batchNodes.getLength(); i++) {
                    Element batch = (Element) batchNodes.item(i);
                    String batchType = batch.getAttribute("type");
                    
                    int count = 0;
                    switch (batchType) {
                        case "customers":
                            count = processCustomersFromNode(batch);
                            break;
                        case "products":
                            count = processProductsFromNode(batch);
                            break;
                        case "orders":
                            count = processOrdersFromNode(batch);
                            break;
                    }
                    
                    importStats.put(batchType, importStats.getOrDefault(batchType, 0) + count);
                }
                
                dbConnection.commit();
                
                int totalRecords = importStats.values().stream().mapToInt(Integer::intValue).sum();
                logImport(totalRecords, "SUCCESS", "Bulk import completed successfully");
                
                return createBulkResponse("SUCCESS", "Bulk import completed", importStats);
            } catch (Exception e) {
                dbConnection.rollback();
                throw e;
            } finally {
                dbConnection.setAutoCommit(true);
            }
        } catch (Exception e) {
            logImport(0, "FAILED", e.getMessage());
            return createResponse("FAILED", "Error processing bulk import: " + e.getMessage(), 0);
        }
    }

